import React from "react";
import './achive.css'

import Typed from 'react-typed';

class Achive extends React.Component{	

	constructor(){
		super()
		this.state={data:0}	
	}

	loadData(){
		fetch('https://raw.githubusercontent.com/angelmacwan/angelmacwan.github.io/master/JSON/achive.json')
		.then(res => res.json())
		.then(data =>{
			this.setState({
				data:data
			})
		})
	}

	render(){	

		if(this.state.data === 0){		
			
			this.loadData()			
			return <div className='achive'>
				<h1>Achievements</h1>
			</div>
		}else{

		

		return <div className='achive'>
			<h1>Achievements</h1>

				<div className="containerach">
						{this.state.data.map( (d,key)=>(
							<div className="elem" key={key}>
								<span className="aName">
								<Typed
									strings={[d.name]}
									typeSpeed={20}
									backSpeed={20}			
									showCursor={false}
									startDelay={100}
									>
								</Typed>
								</span>
								<span className="aClg">
								<Typed
									strings={[d.clg]}
									typeSpeed={60}
									backSpeed={20}			
									showCursor={false}
									startDelay={500}
									>
								</Typed>
								</span>
								<span className="aPos">
								<Typed
									strings={[d.pos]}
									typeSpeed={40}
									backSpeed={20}			
									showCursor={false}
									startDelay={500}
									>
								</Typed>
								</span>
							</div>
						) )}					
				</div>  

			</div>;	
		}
}

}




export default Achive;
