import React from "react";
import "./mywork.css";

class Work extends React.Component{
	constructor(){
		super()
		this.state = {data:0}
	}

	loadData(){
		fetch('https://raw.githubusercontent.com/angelmacwan/angelmacwan.github.io/master/JSON/projects.json')
		.then(res => res.json())
		.then(data =>{
			this.setState({
				data:data
			})
		})
	}

	render(){
		if(this.state.data === 0){
			this.loadData()
			return <div className='work'>
			<h1 className='pageHeading'>My Work</h1>
			</div>;
		}else{
			return (
				<div className='work'>
					<h1 className='pageHeading'>My Work</h1>
		
					<div className='containerWork'>
						
						{this.state.data.map((d, key) => {
							if(d.live === "#"){
								return(						
									<div className='CardWork neuBuldge' key={key}>
										<img alt={d.name} src={`https://raw.githubusercontent.com/angelmacwan/angelmacwan.github.io/master/images/${d.img}`} />
										<span className='cHead'>{d.name}</span>
										<br />
										<span className='cDesc'>{d.tech}</span>
										<br />
										<br />								
										<a href={d.git} target='_blank' className='cardBtn'>
											CODE
										</a>
									</div>
								)
							}else{
								return(						
									<div className='CardWork neuBuldge' key={key}>
										<img alt={d.name} src={`https://raw.githubusercontent.com/angelmacwan/angelmacwan.github.io/master/images/${d.img}`} />
										<span className='cHead'>{d.name}</span>
										<br />
										<span className='cDesc'>{d.tech}</span>
										<br />
										<br />
										
										<a href={d.live} target='_blank' className='cardBtn'>
											LIVE
										</a>									
										<a href={d.git} target='_blank' className='cardBtn'>
											CODE
										</a>
									</div>
								)
							}
						})}		
					</div>
				</div>
			);
		}
	}
}


export default Work;
