import React from "react";
import "./skills.css";

class Skills extends React.Component {

	constructor(){
		super()
		this.state = {data:0}
	}

	loadData(){
		fetch("https://raw.githubusercontent.com/angelmacwan/angelmacwan.github.io/master/JSON/skills.json")
		.then(res => res.json())
		.then(data =>{
			this.setState({
				data:data
			})
		})
	}


	render() {
		if (this.state.data === 0){
			this.loadData()
			return(
				<div className='skills'>
					<h1>Skills</h1>
				</div>
			)
		}else{

			return(
				<div className='skills'>
					<h1>Skills</h1>
					<div className='containerSkills'>

						{this.state.data.map((d, key) => {
							let lists = d.data.split(" , ")
									return(		
										<div className='contentSkills neuBuldge' id={key}>
										<h2> {d.title} </h2>
										<hr className='line' />
											{lists.map( (l,k)=>{
												return(
													<p id={k}>{l}</p>
												)
											} )}
										</div>				
									)
						})}
					</div>
				</div>
			)
			}			
		}	
}

export default Skills;
